// 解析 Anthropic Claude API JSON 回應
const response = $json;
const catalog_id = $('SplitInBatches').first().json.Catalog_ID;

try {
  const text = response.content[0].text;
  // 嘗試解析 JSON（可能包含 markdown code block）
  const jsonStr = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const seoData = JSON.parse(jsonStr);

  return [{
    json: {
      catalog_id,
      seo_title: seoData.seo_title || '',
      seo_description: seoData.seo_description || '',
      seo_keywords: seoData.seo_keywords || '',
      og_title: seoData.og_title || '',
      og_description: seoData.og_description || '',
      cleaned_description: seoData.cleaned_description || '',
      llm_description: seoData.llm_description || '',
      parse_success: true
    }
  }];
} catch (e) {
  return [{
    json: {
      catalog_id,
      error: e.message,
      raw_response: JSON.stringify(response),
      parse_success: false
    }
  }];
}
